-- V2 official HCM Module 8 assessment bank (HCM_M8).
-- Additive / idempotent. Safe on populated V1 DBs. Does not alter historical attempts.

ON CONFLICT ("code") DO UPDATE SET
  "title" = EXCLUDED."title",
  "moduleScope" = EXCLUDED."moduleScope",
  "passThresholdPercent" = EXCLUDED."passThresholdPercent",
  "maxAttempts" = EXCLUDED."maxAttempts",
  "timeLimitSeconds" = EXCLUDED."timeLimitSeconds",
  "definitionJson" = EXCLUDED."definitionJson",
  "updatedAt" = CURRENT_TIMESTAMP;

ON CONFLICT ("assessmentId","questionKey") DO UPDATE SET
  "sequence" = EXCLUDED."sequence",
  "type" = EXCLUDED."type",
  "prompt" = EXCLUDED."prompt",
  "optionsJson" = EXCLUDED."optionsJson",
  "scoringJson" = EXCLUDED."scoringJson";

