INSERT INTO "assessment_definition" ("id","code","title","moduleScope","passThresholdPercent","maxAttempts","timeLimitSeconds","definitionJson","createdAt","updatedAt") VALUES
('assess_hcm_m8','HCM_M8','Évaluation — Ressources humaines et HCM','M8',70,2,2400,'{"kind":"hcm","curriculumVersion":"V2","modules":["M8"],"missions":["M8-M01","M8-M02","M8-M03"],"totalPoints":100,"questionCount":20,"language":"fr"}'::jsonb,CURRENT_TIMESTAMP,CURRENT_TIMESTAMP)
INSERT INTO "assessment_question" ("id","assessmentId","questionKey","sequence","type","prompt","optionsJson","scoringJson") VALUES
('aq_hcm_m8_01','assess_hcm_m8','HCM-M8-Q01',1,'SINGLE_CHOICE','Dans la fiche employé HCM, quelle distinction doit être respectée entre identité légale et identité professionnelle ?','[{"key":"a","label":"L''identité légale (ex. pièce d''identité / NAS) reste au coffre RH; l''identité professionnelle (matricule, courriel) sert aux accès et transactions ERP."},{"key":"b","label":"Le NAS doit figurer sur chaque ticket d''accès pour accélérer le provisionnement."},{"key":"c","label":"L''identité professionnelle remplace l''identité légale dès le premier jour."},{"key":"d","label":"Aucune distinction n''est nécessaire si le gestionnaire connaît la personne."}]'::jsonb,'{"maxPoints":5,"correctKeys":["a"],"curriculumVersion":"V2","module":"M8","mission":"M8-M01","competency":"C-HCM-01","questionKind":"conceptual","difficulty":"intro","tags":["privacy","employee-master","onboarding"],"explanation":"Le moindre besoin impose de séparer données légales RH et identifiants professionnels utilisés pour l''autorisation ERP.","whyAlternativesIncorrect":{"b":"Le NAS est une donnée sensible hors périmètre d''accès ERP.","c":"Les deux coexistent avec des finalités et contrôles distincts.","d":"La connaissance informelle ne remplace pas la gouvernance des données."},"businessRationale":"Une fuite de données légales dans un ticket d''accès crée un risque de confidentialité et de non-conformité.","sourceConcept":"Employee master — legal vs professional identity boundary","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":true}}'::jsonb),
('aq_hcm_m8_02','assess_hcm_m8','HCM-M8-Q02',2,'SINGLE_CHOICE','Samira Benali (OPS-AN-14, DC Montréal) doit être rattachée à Operations. Quel centre de coûts est valide ?','[{"key":"a","label":"CC-FIN-HQ — Finance siège, car « tous les coûts passent par Finance »."},{"key":"b","label":"CC-OPS-MTL — Operations Montréal, aligné au poste et au lieu de travail."},{"key":"c","label":"CC-EXT-PART — partenaire externe, pour mutualiser les coûts."},{"key":"d","label":"Aucun centre de coûts — on le complétera après la première paie."}]'::jsonb,'{"maxPoints":5,"correctKeys":["b"],"curriculumVersion":"V2","module":"M8","mission":"M8-M01","competency":"C-HCM-01","questionKind":"scenario","difficulty":"intermediate","tags":["cost-center","onboarding","finance-impact"],"explanation":"Le centre de coûts doit correspondre à l''affectation organisationnelle réelle (Operations / Montréal).","whyAlternativesIncorrect":{"a":"Hors périmètre Operations; fausse l''imputation et le reporting.","c":"Centre externe invalide pour un employé interne Equinoxe.","d":"Sans centre de coûts, reporting et contrôles financiers sont incomplets."},"businessRationale":"Un mauvais centre de coûts fausse les coûts de mission, les tableaux de bord et les analyses de marge.","sourceConcept":"Cost center assignment validity","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_03','assess_hcm_m8','HCM-M8-Q03',3,'SINGLE_CHOICE','Quelle séquence d''intégration est conforme aux contrôles HCM / ERP ?','[{"key":"a","label":"Créer les accès Admin → créer la fiche → valider l''identité → affecter le poste."},{"key":"b","label":"Activer la paie → affecter le centre de coûts → valider l''identité → créer la fiche."},{"key":"c","label":"Valider l''identité → créer la fiche employé → affecter poste/organisation/centre de coûts → déclencher la demande d''accès à moindre privilège → clôturer les contrôles d''intégration."},{"key":"d","label":"Créer la fiche sans affectation → ouvrir tous les modules → valider l''identité plus tard."}]'::jsonb,'{"maxPoints":5,"correctKeys":["c"],"curriculumVersion":"V2","module":"M8","mission":"M8-M01","competency":"C-HCM-02","questionKind":"sequence","difficulty":"intermediate","tags":["sequence","onboarding","least-privilege"],"explanation":"L''ordre identité → master data → affectations → accès garantit traçabilité, moindre privilège et isolation société.","whyAlternativesIncorrect":{"a":"Les accès ne doivent jamais précéder l''identité et l''affectation.","b":"La paie ne peut pas précéder la fiche et les contrôles d''identité.","d":"Bypass des contrôles d''affectation, d''identité et de moindre privilège."},"businessRationale":"Inverser l''ordre expose l''ERP à des comptes orphelins ou sur-privilegiés.","sourceConcept":"Onboarding control sequence","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_04','assess_hcm_m8','HCM-M8-Q04',4,'SINGLE_CHOICE','Pour un analyste opérations, quelle demande d''accès respecte le moindre privilège ?','[{"key":"a","label":"Admin Finance + création fournisseur « au cas où »."},{"key":"b","label":"Tous les modules en écriture pour gagner du temps la première semaine."},{"key":"c","label":"Accès lecture seule globale entreprise, y compris paie détaillée."},{"key":"d","label":"Lecture Stocks + saisie inventaire cycle, liés au poste OPS-AN-14 et à la demande ONB."}]'::jsonb,'{"maxPoints":5,"correctKeys":["d"],"curriculumVersion":"V2","module":"M8","mission":"M8-M01","competency":"C-HCM-02","questionKind":"scenario","difficulty":"intermediate","tags":["access","least-privilege","onboarding"],"explanation":"L''accès doit être dérivé du poste et de la demande d''intégration, pas d''une commodité opérationnelle.","whyAlternativesIncorrect":{"a":"Accès excessif, hors besoin métier, risque SoD.","b":"Sur-privilège temporaire reste un écart de gouvernance.","c":"La paie détaillée est hors besoin et sensible."},"businessRationale":"Le moindre privilège réduit fraude, erreurs et exposition de données RH/finance.","sourceConcept":"Least-privilege access request","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_05','assess_hcm_m8','HCM-M8-Q05',5,'SINGLE_CHOICE','Un collègue propose d''ajouter le NAS dans le ticket d''accès ACC-REQ « pour vérifier l''identité ». Quelle décision est correcte ?','[{"key":"a","label":"Refuser : le NAS reste au coffre RH; le ticket d''accès utilise matricule/courriel professionnels après validation d''identité."},{"key":"b","label":"Accepter : plus de données dans le ticket = meilleure sécurité."},{"key":"c","label":"Accepter uniquement si le ticket est chiffré par e-mail."},{"key":"d","label":"Reporter la décision au nouvel employé le premier jour."}]'::jsonb,'{"maxPoints":5,"correctKeys":["a"],"curriculumVersion":"V2","module":"M8","mission":"M8-M01","competency":"C-HCM-01","questionKind":"diagnosis_governance","difficulty":"intermediate","tags":["privacy","governance","access"],"explanation":"La validation d''identité RH et le provisionnement d''accès sont des contrôles distincts; le NAS n''appartient pas au ticket d''accès.","whyAlternativesIncorrect":{"b":"Plus de données sensibles augmente le risque, sans améliorer l''autorisation.","c":"Le canal ne justifie pas d''élargir le périmètre de données.","d":"La gouvernance des données sensibles n''est pas déléguée à l''employé."},"businessRationale":"La minimisation des données sensibles est un contrôle de confidentialité non négociable.","sourceConcept":"Privacy boundary on access tickets","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":true}}'::jsonb),
('aq_hcm_m8_06','assess_hcm_m8','HCM-M8-Q06',6,'SINGLE_CHOICE','On propose Marc Dubois (société partenaire ThermoControl) comme gestionnaire de Samira (Equinoxe). Quelle analyse est correcte ?','[{"key":"a","label":"Valide si Marc connaît bien le métier opérations."},{"key":"b","label":"Invalide : le gestionnaire doit appartenir à la même société légale; choisir un manager Equinoxe (ex. Julie Tremblay)."},{"key":"c","label":"Valide temporairement jusqu''à la première évaluation."},{"key":"d","label":"Valide si le centre de coûts est partagé."}]'::jsonb,'{"maxPoints":5,"correctKeys":["b"],"curriculumVersion":"V2","module":"M8","mission":"M8-M01","competency":"C-HCM-02","questionKind":"scenario","difficulty":"advanced","tags":["company-isolation","manager","onboarding"],"explanation":"L''affectation organisationnelle est bornée par la société légale pour approbations, isolation et audit.","whyAlternativesIncorrect":{"a":"La compétence métier ne remplace pas l''isolation société.","c":"Une affectation cross-company reste non conforme.","d":"Le partage de coûts n''autorise pas un manager hors société."},"businessRationale":"Un manager hors société casse les workflows d''approbation et la séparation des entités.","sourceConcept":"Cross-company manager rejection","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_07','assess_hcm_m8','HCM-M8-Q07',7,'SINGLE_CHOICE','Pourquoi un employé ne peut-il pas être activé sans affectation organisationnelle valide (poste, département, manager, centre de coûts, lieu) ?','[{"key":"a","label":"Parce que l''interface ERP masque alors les boutons de paie."},{"key":"b","label":"Parce que le certificat Gold l''interdit explicitement."},{"key":"c","label":"Parce que sans affectation, approbations, imputation des coûts, reporting et contrôles d''accès ne sont pas fiables."},{"key":"d","label":"Parce que le NAS devient obligatoire seulement après activation."}]'::jsonb,'{"maxPoints":5,"correctKeys":["c"],"curriculumVersion":"V2","module":"M8","mission":"M8-M01","competency":"C-HCM-01","questionKind":"conceptual","difficulty":"intermediate","tags":["organizational-assignment","activation","controls"],"explanation":"L''affectation organisationnelle est le socle des workflows, de la finance analytique et de l''autorisation.","whyAlternativesIncorrect":{"a":"Ce n''est pas une raison UI; c''est un contrôle métier.","b":"Hors sujet certification; enjeu HCM/ERP.","d":"Ne répond pas au besoin d''affectation organisationnelle."},"businessRationale":"Activer sans rattachement crée des employés « orphelins » impossibles à gouverner.","sourceConcept":"Organizational assignment prerequisite","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_08','assess_hcm_m8','HCM-M8-Q08',8,'SINGLE_CHOICE','Quelle séquence est correcte pour traiter une absence avec impact opérationnel ?','[{"key":"a","label":"Calculer le coût → poster l''absence → demander l''approbation → choisir le type."},{"key":"b","label":"Saisir les heures présentes en double → approuver → ignorer le coût."},{"key":"c","label":"Planifier 12 h HS d''abord → soumettre l''absence sans type → approuver ensuite."},{"key":"d","label":"Soumettre la demande → valider le type d''absence → obtenir l''approbation → mettre à jour horaire/capacité → évaluer remplacement/HS → calculer l''impact financier → documenter."}]'::jsonb,'{"maxPoints":5,"correctKeys":["d"],"curriculumVersion":"V2","module":"M8","mission":"M8-M02","competency":"C-HCM-03","questionKind":"sequence","difficulty":"intermediate","tags":["sequence","absence","payroll-impact"],"explanation":"L''absence suit un cycle contrôlé : demande, type, approbation, capacité, continuité, finance, documentation.","whyAlternativesIncorrect":{"a":"L''approbation et le type doivent précéder l''enregistrement.","b":"Double saisie et oubli financier sont des écarts.","c":"Bypass du type, de l''approbation et de la politique HS."},"businessRationale":"Sauter l''approbation ou le calcul de coût expose le service et la paie à des erreurs.","sourceConcept":"Absence-to-finance control sequence","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_09','assess_hcm_m8','HCM-M8-Q09',9,'SINGLE_CHOICE','ABS-REQ-7781 (maladie courte durée, 16 h) est encore « en attente d''approbation ». Quelle action est conforme ?','[{"key":"a","label":"Faire approuver par le manager, puis enregistrer l''absence sur l''horaire avant d''ajuster capacité et coûts."},{"key":"b","label":"Poster l''absence immédiatement pour ne pas bloquer le planning."},{"key":"c","label":"Reclasser en congé parental sans justificatif pour simplifier."},{"key":"d","label":"Supprimer la demande et saisir 16 h présentes."}]'::jsonb,'{"maxPoints":5,"correctKeys":["a"],"curriculumVersion":"V2","module":"M8","mission":"M8-M02","competency":"C-HCM-03","questionKind":"scenario","difficulty":"intermediate","tags":["absence-approval","absence-type","controls"],"explanation":"L''approbation manager et le type d''absence valide précèdent toute mise à jour d''horaire.","whyAlternativesIncorrect":{"b":"Une absence non approuvée ne doit pas être postée.","c":"Type d''absence incorrect et non justifié.","d":"Falsifie la présence et la capacité réelle."},"businessRationale":"Poster sans approbation fausse la paie, la capacité et l''audit des absences.","sourceConcept":"Absence approval before posting","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_10','assess_hcm_m8','HCM-M8-Q10',10,'SINGLE_CHOICE','Horaire planifié 40 h; absence approuvée 16 h; besoin opérationnel 36 h. Combien d''heures supplémentaires sont requises pour combler l''écart de capacité ?','[{"key":"a","label":"8 h (politique max confondue avec le besoin)."},{"key":"b","label":"12 h (capacité restante 24 h; écart 36 − 24 = 12)."},{"key":"c","label":"16 h (égale à l''absence)."},{"key":"d","label":"36 h (besoin total sans soustraire la capacité restante)."}]'::jsonb,'{"maxPoints":5,"correctKeys":["b"],"curriculumVersion":"V2","module":"M8","mission":"M8-M02","competency":"C-HCM-04","questionKind":"quantitative","difficulty":"advanced","tags":["quantitative","capacity","overtime"],"explanation":"Capacité restante = 40 − 16 = 24 h; écart = 36 − 24 = 12 h d''HS requises.","whyAlternativesIncorrect":{"a":"8 h est un plafond politique, pas le calcul de l''écart 36−24.","c":"L''absence n''est pas égale au besoin d''HS.","d":"Ignore les 24 h de capacité régulière restante."},"businessRationale":"Quantifier l''écart évite sous/sur-couverture et erreurs de coût.","sourceConcept":"Capacity gap and overtime hours","quantitative":{"inputs":{"plannedHours":40,"approvedAbsenceHours":16,"operationalRequirementHours":36},"expected":{"remainingRegularCapacityHours":24,"capacityGapOvertimeHours":12}},"analytics":{"quantitative":true,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_11','assess_hcm_m8','HCM-M8-Q11',11,'SINGLE_CHOICE','Avec 12 h d''HS, taux normal 28 $/h et majoration 1,5 : quel est le coût incrémental des heures supplémentaires ?','[{"key":"a","label":"336 $ (12 × 28, sans majoration)."},{"key":"b","label":"420 $ (10 × 28 × 1,5)."},{"key":"c","label":"504 $ (taux HS 28 × 1,5 = 42; 12 × 42 = 504)."},{"key":"d","label":"672 $ (12 × 28 × 2)."}]'::jsonb,'{"maxPoints":5,"correctKeys":["c"],"curriculumVersion":"V2","module":"M8","mission":"M8-M02","competency":"C-HCM-04","questionKind":"quantitative","difficulty":"advanced","tags":["quantitative","overtime","cost-center"],"explanation":"Taux HS = 28 × 1,5 = 42 $/h; coût incrémental = 12 × 42 = 504 $ (calcul déterministe, sans arrondi).","whyAlternativesIncorrect":{"a":"Omet le multiplicateur 1,5.","b":"Utilise un nombre d''heures incorrect.","d":"Multiplicateur erroné (2 au lieu de 1,5)."},"businessRationale":"Le coût incrémental doit être imputé au centre de coûts pour la décision de continuité.","sourceConcept":"Incremental overtime cost","quantitative":{"inputs":{"overtimeHours":12,"normalHourlyCost":28,"overtimeMultiplier":1.5},"expected":{"overtimeHourlyCost":42,"incrementalOvertimeCost":504}},"analytics":{"quantitative":true,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_12','assess_hcm_m8','HCM-M8-Q12',12,'SINGLE_CHOICE','La feuille de temps contient 16 h « présentes » le même jour que 16 h d''absence approuvée. Quelle interprétation est correcte ?','[{"key":"a","label":"C''est acceptable si le total hebdomadaire reste 40 h."},{"key":"b","label":"C''est utile pour documenter la motivation de l''employé."},{"key":"c","label":"Cela augmente automatiquement la capacité opérationnelle."},{"key":"d","label":"C''est une double saisie invalide : présence et absence ne peuvent se chevaucher; corriger avant paie et capacité."}]'::jsonb,'{"maxPoints":5,"correctKeys":["d"],"curriculumVersion":"V2","module":"M8","mission":"M8-M02","competency":"C-HCM-03","questionKind":"interpretation","difficulty":"intermediate","tags":["timesheet","duplicate","payroll-impact"],"explanation":"Présence et absence sur le même intervalle sont mutuellement exclusives; la correction protège paie et capacité.","whyAlternativesIncorrect":{"a":"Le total masque une double saisie incohérente.","b":"Hors finalité timesheet; risque d''erreur de paie.","c":"Une double saisie n''ajoute pas de capacité réelle."},"businessRationale":"Les doublons timesheet génèrent surpaiement et fausse couverture de service.","sourceConcept":"Duplicate timesheet detection","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_13','assess_hcm_m8','HCM-M8-Q13',13,'SINGLE_CHOICE','Capacité régulière restante 24 h, besoin 36 h, relève qualifiée indisponible. Quel risque faut-il prioriser dans la décision ?','[{"key":"a","label":"Risque de service (inventaire/cycle retardé) et risque financier (HS / remplacement), à documenter avec le coût incrémental."},{"key":"b","label":"Aucun risque si l''absence est de type « maladie »."},{"key":"c","label":"Risque uniquement esthétique sur le tableau de bord RH."},{"key":"d","label":"Risque nul tant que le certificat Silver est obtenu."}]'::jsonb,'{"maxPoints":5,"correctKeys":["a"],"curriculumVersion":"V2","module":"M8","mission":"M8-M02","competency":"C-HCM-04","questionKind":"interpretation","difficulty":"advanced","tags":["service-risk","financial-impact","interpretation"],"explanation":"L''écart 12 h crée un risque de continuité de service et un coût HS qu''il faut rendre explicites.","whyAlternativesIncorrect":{"b":"Le type n''élimine pas l''écart de capacité.","c":"L''impact est opérationnel et financier, pas cosmétique.","d":"Hors sujet certification."},"businessRationale":"Ignorer l''impact financier ou opérationnel conduit à des décisions non gouvernées.","sourceConcept":"Operational and financial risk from capacity gap","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_14','assess_hcm_m8','HCM-M8-Q14',14,'SINGLE_CHOICE','La politique limite les HS à 8 h/semaine, mais le calcul de besoin indique 12 h. Quelle conduite est correcte ?','[{"key":"a","label":"Poster 12 h d''HS sans escalade, car le besoin opérationnel prime toujours."},{"key":"b","label":"Ne pas dépasser silencieusement la politique : documenter l''écart, escalader (remplacement, priorisation, dérogation formelle) et chiffrer le coût."},{"key":"c","label":"Ignorer le besoin et laisser le service sans couverture."},{"key":"d","label":"Recoder 4 h d''HS en présence pour masquer le dépassement."}]'::jsonb,'{"maxPoints":5,"correctKeys":["b"],"curriculumVersion":"V2","module":"M8","mission":"M8-M02","competency":"C-HCM-04","questionKind":"conceptual","difficulty":"intermediate","tags":["overtime-policy","governance","financial-impact"],"explanation":"Le plafond politique est un contrôle; tout dépassement exige escalade et traçabilité, pas de contournement.","whyAlternativesIncorrect":{"a":"Le besoin ne légitime pas le dépassement silencieux de politique.","c":"L''inaction non documentée n''est pas une gouvernance acceptable.","d":"Falsification de données de temps."},"businessRationale":"La conformité HS protège coûts, santé organisationnelle et auditabilité.","sourceConcept":"Overtime policy limit governance","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":true}}'::jsonb),
('aq_hcm_m8_15','assess_hcm_m8','HCM-M8-Q15',15,'SINGLE_CHOICE','Quelle séquence d''évaluation des compétences est conforme ?','[{"key":"a","label":"Appliquer la reco IA comme décision finale → collecter des preuves ensuite."},{"key":"b","label":"Définir un plan de formation générique → noter sans preuves → valider plus tard."},{"key":"c","label":"Définir le niveau attendu → collecter des preuves → évaluer le niveau observé → identifier l''écart → définir une action de développement mesurable → validation manager → suivi."},{"key":"d","label":"Utiliser des données sensibles hors emploi pour prédire le potentiel → noter → former."}]'::jsonb,'{"maxPoints":5,"correctKeys":["c"],"curriculumVersion":"V2","module":"M8","mission":"M8-M03","competency":"C-HCM-05","questionKind":"sequence","difficulty":"intermediate","tags":["sequence","competency","evidence"],"explanation":"La boucle compétence exige attendu, preuves, observé, écart, action, validation humaine et suivi.","whyAlternativesIncorrect":{"a":"L''IA est advisory; les preuves précèdent le jugement.","b":"Le plan doit découler des écarts evidencés.","d":"Données protégées / non pertinentes interdites pour la décision."},"businessRationale":"Sans preuves et validation manager, l''évaluation n''est ni équitable ni auditable.","sourceConcept":"Competency review sequence","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_16','assess_hcm_m8','HCM-M8-Q16',16,'SINGLE_CHOICE','Un manager attribue « expert » sans livrable, observation ni feedback documenté. Quelle conduite est correcte ?','[{"key":"a","label":"Accepter la note : l''intuition managériale suffit."},{"key":"b","label":"Demander à l''IA de confirmer automatiquement la note."},{"key":"c","label":"Convertir immédiatement la note en promotion."},{"key":"d","label":"Rejeter la note non supportée; exiger des preuves avant de figer le niveau observé et le plan."}]'::jsonb,'{"maxPoints":5,"correctKeys":["d"],"curriculumVersion":"V2","module":"M8","mission":"M8-M03","competency":"C-HCM-05","questionKind":"scenario","difficulty":"advanced","tags":["evidence","fairness","competency"],"explanation":"Toute cotation de compétence doit reposer sur des preuves observables et traçables.","whyAlternativesIncorrect":{"a":"Les notes sans preuves ne sont pas défendables.","b":"L''IA ne remplace pas les preuves ni le jugement responsable.","c":"Décision d''emploi sans fondement evidencé."},"businessRationale":"Les notes sans preuves exposent à l''iniquité et aux décisions non auditables.","sourceConcept":"Unsupported rating rejection","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_17','assess_hcm_m8','HCM-M8-Q17',17,'SINGLE_CHOICE','Le coach IA recommande une formation. Un collègue veut l''appliquer comme décision finale de développement. Que faire ?','[{"key":"a","label":"Traiter la reco comme advisory : le manager reste responsable; valider l''alignement aux écarts evidencés avant d''agir."},{"key":"b","label":"Appliquer automatiquement la reco pour éviter le biais humain."},{"key":"c","label":"Ignorer toute preuve humaine si l''IA est confiante."},{"key":"d","label":"Utiliser la reco IA pour contourner l''approbation manager."}]'::jsonb,'{"maxPoints":5,"correctKeys":["a"],"curriculumVersion":"V2","module":"M8","mission":"M8-M03","competency":"C-HCM-06","questionKind":"diagnosis_governance","difficulty":"advanced","tags":["ai-governance","human-accountability","bias"],"explanation":"Les recommandations IA sont consultatives; la décision d''emploi/développement reste humaine et justifiée.","whyAlternativesIncorrect":{"b":"L''automatisation sans jugement humain déplace la responsabilité.","c":"La confiance modèle ne remplace pas les preuves métier.","d":"Bypass de la responsabilité managériale."},"businessRationale":"Préserver l''accountability évite les décisions opaques et les biais non contrôlés.","sourceConcept":"AI advisory vs human accountability","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":true}}'::jsonb),
('aq_hcm_m8_18','assess_hcm_m8','HCM-M8-Q18',18,'SINGLE_CHOICE','Quelle règle s''applique aux données sensibles / protégées dans une décision d''évolution ou de performance ?','[{"key":"a","label":"Elles peuvent départager deux candidats si le modèle IA les juge utiles."},{"key":"b","label":"Elles ne doivent pas déterminer les décisions d''emploi; seules des preuves de performance/compétences pertinentes comptent."},{"key":"c","label":"Elles sont obligatoires pour prouver l''équité algorithmique."},{"key":"d","label":"Elles remplacent le plan de développement si absentes."}]'::jsonb,'{"maxPoints":5,"correctKeys":["b"],"curriculumVersion":"V2","module":"M8","mission":"M8-M03","competency":"C-HCM-06","questionKind":"conceptual","difficulty":"intermediate","tags":["privacy","fairness","governance"],"explanation":"Les décisions d''emploi reposent sur des preuves professionnelles pertinentes, jamais sur des attributs sensibles.","whyAlternativesIncorrect":{"a":"Les traits protégés / non pertinents ne doivent pas fonder la décision.","c":"L''équité ne s''obtient pas en injectant des données sensibles.","d":"Sans rapport avec l''objectif de développement mesurable."},"businessRationale":"Cette borne protège l''équité, la conformité et la confiance institutionnelle.","sourceConcept":"Sensitive data exclusion from employment decisions","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":true}}'::jsonb),
('aq_hcm_m8_19','assess_hcm_m8','HCM-M8-Q19',19,'SINGLE_CHOICE','Les preuves montrent un niveau « intermédiaire » en analyse, mais la note saisie est « expert » sans nouvel élément. Quelle interprétation est correcte ?','[{"key":"a","label":"La note expert prévaut car plus favorable à l''employé."},{"key":"b","label":"La contradiction prouve que les preuves sont inutiles."},{"key":"c","label":"Écart contradictoire : recalibrer le niveau observé sur les preuves, documenter, puis définir l''écart et l''action."},{"key":"d","label":"Laisser l''IA choisir la note la plus haute."}]'::jsonb,'{"maxPoints":5,"correctKeys":["c"],"curriculumVersion":"V2","module":"M8","mission":"M8-M03","competency":"C-HCM-05","questionKind":"interpretation","difficulty":"advanced","tags":["evidence","explainability","competency-gap"],"explanation":"En cas de contradiction, les preuves observables gouvernent; la note est corrigée avant le plan.","whyAlternativesIncorrect":{"a":"Une note favorable non supportée reste non conforme.","b":"Les preuves sont le fondement; la note doit s''y aligner.","d":"L''IA ne tranche pas les contradictions sans preuves."},"businessRationale":"L''explicabilité exige la cohérence entre preuves, niveau et actions.","sourceConcept":"Contradictory competency evidence handling","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb),
('aq_hcm_m8_20','assess_hcm_m8','HCM-M8-Q20',20,'SINGLE_CHOICE','Après identification d''un écart en « analyse de données », quelle action de développement est conforme ?','[{"key":"a","label":"Inscrire à une formation vente terrain sans lien avec l''écart."},{"key":"b","label":"Clôturer sans objectif mesurable « pour garder de la flexibilité »."},{"key":"c","label":"Assimiler performance actuelle et potentiel de leadership sans preuve."},{"key":"d","label":"Définir un objectif mesurable lié à l''écart (ex. produire 2 analyses inventaire validées), avec échéance et validation manager."}]'::jsonb,'{"maxPoints":5,"correctKeys":["d"],"curriculumVersion":"V2","module":"M8","mission":"M8-M03","competency":"C-HCM-06","questionKind":"conceptual","difficulty":"intermediate","tags":["development-plan","competency-gap","accountability"],"explanation":"L''action de développement doit correspondre à l''écart evidencé, être mesurable et validée par le manager.","whyAlternativesIncorrect":{"a":"Formation non alignée à l''écart identifié.","b":"Sans objectif mesurable, le suivi est impossible.","c":"Performance et potentiel ne sont pas équivalents."},"businessRationale":"Un plan aligné et mesurable rend le progrès auditable et équitable.","sourceConcept":"Gap-aligned measurable development objective","quantitative":null,"analytics":{"quantitative":false,"privacyGovernance":false}}'::jsonb)
